def to_twos_complement(n, bits):
    """Convert integer n to n-bit 2's complement"""
    if n >= 0:
        return format(n, f'0{bits}b')
    else:
        # For negative: add 2^bits, then convert
        return format((1 << bits) + n, f'0{bits}b')

def from_twos_complement(binary_str):
    """Convert n-bit 2's complement to decimal"""
    bits = len(binary_str)
    value = int(binary_str, 2)
    # If negative (MSB is 1), subtract 2^bits
    if value >= (1 << (bits - 1)):
        value -= (1 << bits)
    return value

# Example: -47 in 8-bit 2's complement
print(to_twos_complement(-47, 8))  # Output: 11010001
print(from_twos_complement('11010001'))  # Output: -47

#include <stdio.h>

typedef union {
    float f;
    unsigned int i;
} FloatBits;

unsigned int floatToIEEE754(float value) {
    FloatBits fb;
    fb.f = value;
    return fb.i;
}

void printBinary(unsigned int n, int bits) {
    for (int i = bits - 1; i >= 0; i--) {
        printf("%d", (n >> i) & 1);
        if (i == 31 || i == 23) printf(" ");
    }
}

int main() {
    float num = -5.75f;
    unsigned int ieee = floatToIEEE754(num);

    printf("Number: %.2f\n", num);
    printf("IEEE 754: ");
    printBinary(ieee, 32);
    printf("\nHex: %08X\n", ieee);

    // Manual verification for -5.75:
    // Sign: 1 (negative)
    // 5.75 = 101.11 binary = 1.011 × 2^2
    // Exponent: 2 + 127 = 129 = 10000001
    // Mantissa: 0111000... = 0111 then zeros
    // Result: 1 10000001 01110000000000000000000

